const item = $input.first();
const d = $('Code in JavaScript').first().json;
const vtData = item.json;

let vt_archivo = null;

try {
  if (!item.error && !vtData.error) {
    const attrs = vtData.data?.attributes || {};
    const stats = attrs.last_analysis_stats || {};
    const results = attrs.last_analysis_results || {};

    const malicioso = stats.malicious || 0;
    const sospechoso = stats.suspicious || 0;
    const inofensivo = stats.undetected || 0;
    const inofensivo2 = stats.harmless || 0;
    const timeout = stats.timeout || 0;
    const total = malicioso + sospechoso + inofensivo + inofensivo2 + timeout;

    const motores_maliciosos = Object.entries(results)
      .filter(([_, v]) => v && v.category === 'malicious')
      .map(([motor, v]) => ({ motor, resultado: v.result || null }));

    vt_archivo = {
      sha256: vtData.data?.id || null,
      nombre: attrs.meaningful_name || null,
      tipo: attrs.type_description || null,
      malicioso,
      sospechoso,
      inofensivo: inofensivo + inofensivo2,
      total_motores: total,
      detecciones_resumen: `${malicioso}/${total}`,
      motores_maliciosos,
      fecha_analisis: attrs.last_analysis_date || null
    };
  }
} catch (e) {
  vt_archivo = null;
}

